import{c as t,Q as n,j as a,m as o}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"地形生成:种子、噪声与确定性世界","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/02-地形生成-种子噪声与确定性世界.md","filePath":"minecraftLearning/02-地形生成-种子噪声与确定性世界.md","lastUpdated":1781674740000}'),e={name:"minecraftLearning/02-地形生成-种子噪声与确定性世界.md"};function p(r,s,i,l,c,d){return n(),a("div",null,[...s[0]||(s[0]=[o(`<h1 id="地形生成-种子、噪声与确定性世界" tabindex="-1">地形生成:种子、噪声与确定性世界 <a class="header-anchor" href="#地形生成-种子、噪声与确定性世界" aria-label="Permalink to &quot;地形生成:种子、噪声与确定性世界&quot;">​</a></h1><p>Minecraft 号称&quot;无限世界&quot;,你可以朝一个方向走上几天,脚下永远有新地形冒出来。但这里有个绕不过去的工程矛盾:<strong>无限的世界,装不进有限的硬盘</strong>。如果地形是预先画好存下来的,那存到第几个 TB 才算&quot;无限&quot;?</p><p>答案是:<strong>地形根本不存。它是在你走到时,被一个函数当场算出来的。</strong> 这一篇讲清楚这个函数怎么来的、为什么它能保证你和你朋友看到的世界一模一样,以及一块石头从&quot;虚空&quot;变成&quot;真实方块&quot;要经过哪些流水线阶段。</p><blockquote><p>一句话先记住:<strong>地形 = f(种子, 坐标)。同一个种子、同一个坐标,永远算出同一个方块。</strong> 所以世界不用存,只有被你改动过的方块才需要落盘。生成是确定的,存储是增量的。</p></blockquote><hr><h2 id="一、为什么不能-预先画好存下来" tabindex="-1">一、为什么不能&quot;预先画好存下来&quot; <a class="header-anchor" href="#一、为什么不能-预先画好存下来" aria-label="Permalink to &quot;一、为什么不能&quot;预先画好存下来&quot;&quot;">​</a></h2><p>先把朴素方案枪毙掉。假设我们像存图片一样存地形:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>世界 = 一个超大三维数组</span></span>
<span class="line"><span>存盘 = 把整个数组写进文件</span></span></code></pre></div><p>问题立刻爆炸:</p><table tabindex="0"><thead><tr><th>朴素做法</th><th>后果</th></tr></thead><tbody><tr><td>世界有限</td><td>那就不是&quot;无限世界&quot;,走到边界就掉下去</td></tr><tr><td>世界无限</td><td>文件无限大,根本写不完也存不下</td></tr><tr><td>玩家只逛了 0.001%</td><td>却要为 100% 的地形付出存储</td></tr></tbody></table><p>真正的世界 99.99% 是玩家<strong>从没去过、也永远不会改</strong>的区域。为这些区域存数据,纯属浪费。于是设计目标变成:</p><blockquote><p><strong>没去过的地方不占一个字节;去过、且改过的地方才存。中间的&quot;原始地形&quot;随时能重新算出来。</strong></p></blockquote><p>要做到&quot;随时能重新算出来&quot;,就需要一个<strong>确定性函数</strong>:给它一个坐标,它吐出那里应该是什么方块,而且每次吐的都一样。这个函数的核心,就是<strong>噪声(noise)</strong>。</p><hr><h2 id="二、噪声-可控的随机" tabindex="-1">二、噪声:可控的随机 <a class="header-anchor" href="#二、噪声-可控的随机" aria-label="Permalink to &quot;二、噪声:可控的随机&quot;">​</a></h2><p>直接用 <code>random()</code> 生成地形是不行的——它给出的是<strong>白噪声</strong>,每个点和相邻点毫无关系,生成出来是一片杂乱的&quot;电视雪花&quot;,不是山脉。</p><p>地形需要的是<strong>平滑的随机</strong>:相邻坐标的高度应该接近,整体又有起伏。这就是 <strong>Perlin 噪声 / Simplex 噪声</strong>解决的问题。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>白噪声(random):        平滑噪声(Perlin/Simplex):</span></span>
<span class="line"><span> █ ░ █ ░ ░ █ ░ █          ░ ▒ ▓ █ ▓ ▒ ░ ░</span></span>
<span class="line"><span> ░ █ ░ █ █ ░ █ ░          ▒ ▓ █ █ ▓ ▒ ▒ ░</span></span>
<span class="line"><span> 像素级抖动,无地貌        连绵起伏,像山和谷</span></span></code></pre></div><p>Minecraft 的演进路线:</p><table tabindex="0"><thead><tr><th>时期</th><th>用的噪声</th><th>备注</th></tr></thead><tbody><tr><td>早期</td><td><strong>Perlin 噪声</strong>(Ken Perlin 1983)</td><td>经典,但有方向性伪影</td></tr><tr><td>后来</td><td><strong>Simplex / OpenSimplex</strong></td><td>更少方向伪影、更高维更快;OpenSimplex 是为规避 Simplex 专利的开源变体</td></tr></tbody></table><p>噪声函数的关键性质,正是地形生成的命根子:</p><blockquote><p><code>noise(x, z)</code> 是一个<strong>纯函数</strong>——只要输入坐标不变,输出永远不变,且与&quot;先访问哪里、后访问哪里&quot;无关。</p></blockquote><p>这意味着你可以<strong>乱序</strong>地、<strong>重复</strong>地查询任意坐标,结果完全一致。地形因此可以&quot;走到哪算到哪&quot;,不依赖任何已生成的历史。</p><hr><h2 id="三、种子-让-确定-可复制" tabindex="-1">三、种子:让&quot;确定&quot;可复制 <a class="header-anchor" href="#三、种子-让-确定-可复制" aria-label="Permalink to &quot;三、种子:让&quot;确定&quot;可复制&quot;">​</a></h2><p>光有噪声还不够。如果每个存档都用同一套噪声,所有世界就长得一模一样了。所以引入<strong>种子(seed)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最终地形 = noise(seed 扰动后的坐标空间)</span></span></code></pre></div><p>种子的作用是<strong>给噪声函数换一套坐标偏移/排列</strong>,于是:</p><ul><li><strong>同一个种子</strong> → 同一个世界。你把种子发给朋友,他生成出的出生点、村庄、地形和你<strong>逐方块相同</strong>(同版本下)。</li><li><strong>不同种子</strong> → 完全不同的世界。</li></ul><p>这就是为什么社区里能流传&quot;种子号&quot;:一串数字就完整编码了一个无限世界的全部原始地貌。<strong>世界的信息量被压缩进了&quot;种子 + 生成算法&quot;里</strong>,而不是存在文件里。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的存档真正存的:</span></span>
<span class="line"><span>  ┌─────────────────────────────┐</span></span>
<span class="line"><span>  │ 种子(决定原始地形)         │  ← 几个字节</span></span>
<span class="line"><span>  │ + 你改动过的方块(挖矿/建造)│  ← 增量,只存 diff</span></span>
<span class="line"><span>  └─────────────────────────────┘</span></span>
<span class="line"><span>原始地形本身 = 0 字节,需要时用种子重算</span></span></code></pre></div><hr><h2 id="四、多层噪声叠加-从一条曲线到一个世界" tabindex="-1">四、多层噪声叠加:从一条曲线到一个世界 <a class="header-anchor" href="#四、多层噪声叠加-从一条曲线到一个世界" aria-label="Permalink to &quot;四、多层噪声叠加:从一条曲线到一个世界&quot;">​</a></h2><p>单层噪声只能给你一个&quot;高度图&quot;——平滑但单调。真实地形要同时表达<strong>大尺度的山脉</strong>和<strong>小尺度的碎石起伏</strong>。做法是<strong>多层噪声叠加(octaves)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高度(x,z) =  1.0 * noise(x/256, z/256)   // 低频:大陆、山脉走向</span></span>
<span class="line"><span>          + 0.5 * noise(x/64,  z/64)    // 中频:丘陵</span></span>
<span class="line"><span>          + 0.25* noise(x/16,  z/16)    // 高频:地表碎起伏</span></span>
<span class="line"><span>          + ...</span></span></code></pre></div><p>工程直觉就三个旋钮:</p><table tabindex="0"><thead><tr><th>旋钮</th><th>含义</th><th>调大的效果</th></tr></thead><tbody><tr><td><strong>频率 frequency</strong></td><td>坐标被除以的尺度</td><td>频率高 → 起伏密集、细碎</td></tr><tr><td><strong>振幅 amplitude</strong></td><td>这一层的权重</td><td>振幅大 → 这一层主导地貌</td></tr><tr><td><strong>octave 层数</strong></td><td>叠几层</td><td>层多 → 既有大山又有细节</td></tr></tbody></table><p>通常每加一层,<strong>频率翻倍、振幅减半</strong>(这种叠加方式叫 fractal/fBm)。低频层管&quot;大势&quot;,高频层管&quot;细节&quot;,叠起来就有了既宏观又精致的地貌。</p><h3 id="不只是高度-气候场" tabindex="-1">不只是高度:气候场 <a class="header-anchor" href="#不只是高度-气候场" aria-label="Permalink to &quot;不只是高度:气候场&quot;">​</a></h3><p>Minecraft 现代地形(1.18 重写后)不是只算一个高度,而是同时算<strong>好几张独立的噪声场</strong>,再用它们共同决定每个位置:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>温度场 temperature ─┐</span></span>
<span class="line"><span>湿度场 humidity    ─┤</span></span>
<span class="line"><span>大陆度 continentalness ─┼──►  查&quot;气候 → 生物群系&quot;表  ──►  这里是沙漠?雪原?丛林?</span></span>
<span class="line"><span>侵蚀度 erosion    ─┤</span></span>
<span class="line"><span>怪异度 weirdness  ─┘</span></span></code></pre></div><ul><li><strong>生物群系不再是&quot;先画板块再填&quot;</strong>,而是&quot;算出这点的气候坐标,再去多维表里查它落在哪个 biome&quot;。</li><li>同一套噪声还驱动<strong>矿脉分布</strong>(不同矿在不同高度/密度生成)和<strong>洞穴</strong>(用 3D 噪声直接在实心区域&quot;挖空&quot;出隧道与巨洞,即所谓 noise caves)。</li></ul><p>注意一个维度差异:<strong>高度图是 2D 噪声</strong>(每个 x,z 一个值),而<strong>洞穴是 3D 噪声</strong>(每个 x,y,z 一个值,决定该点是石头还是空气)。3D 噪声更贵,但能造出 2D 高度图永远做不出的悬空洞穴和拱桥。</p><hr><h2 id="五、生成是分阶段的流水线-不是一锤子" tabindex="-1">五、生成是分阶段的流水线,不是一锤子 <a class="header-anchor" href="#五、生成是分阶段的流水线-不是一锤子" aria-label="Permalink to &quot;五、生成是分阶段的流水线,不是一锤子&quot;">​</a></h2><p>你可能以为&quot;生成一个 chunk&quot;是一个原子操作:输入坐标,输出完整地形。<strong>不是。</strong> 因为有些结构是<strong>跨 chunk</strong> 的——一个村庄、一条洞穴、一棵树,可能横跨好几个 chunk 的边界。</p><p>如果每个 chunk 各自独立地&quot;一次性生成完&quot;,边界处就会对不上:村庄被切成两半、洞穴在 chunk 边界突然截断。</p><p>为了解决这个,Minecraft 把生成拆成<strong>一连串阶段(ChunkStatus)</strong>,每个 chunk 像在流水线上一格格往前走:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>empty            （还什么都没有）</span></span>
<span class="line"><span>  → structure_starts   （决定这里要不要起一个村庄/要塞的&quot;种子点&quot;）</span></span>
<span class="line"><span>  → structure_references</span></span>
<span class="line"><span>  → biomes             （确定生物群系）</span></span>
<span class="line"><span>  → noise              （用噪声填出石头/空气的基础地形）</span></span>
<span class="line"><span>  → surface            （铺地表:草、沙、雪）</span></span>
<span class="line"><span>  → carvers            （雕刻洞穴、峡谷)</span></span>
<span class="line"><span>  → features           （撒树木、矿脉、植被、结构主体）</span></span>
<span class="line"><span>  → light              （计算光照)</span></span>
<span class="line"><span>  → spawn</span></span>
<span class="line"><span>  → full               （完工,可被游戏逻辑使用)</span></span></code></pre></div><p>关键约束:</p><blockquote><p><strong>一个 chunk 要推进到某个阶段,它周围的邻居 chunk 必须先到达前一个阶段。</strong></p></blockquote><p>比如要给中心 chunk 跑 <code>features</code>(种树、放村庄房子),引擎需要保证它周围一圈邻居都已经到了 <code>noise</code>/<code>surface</code>,这样跨边界的结构才能正确地&quot;画&quot;到邻居身上。这就是为什么生成新区域时,引擎实际上在<strong>同时推进一整片 chunk 的阶段</strong>,像一个向外扩散的波纹,而不是孤立地一个一个生成。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>中心要 features,必须邻居先就位:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  noise noise noise</span></span>
<span class="line"><span>  noise [feat] noise      ← 中心能种跨界的树/村庄,</span></span>
<span class="line"><span>  noise noise noise          是因为外圈已经有地形可以&quot;画&quot;上去</span></span></code></pre></div><p>这也是&quot;卡在生成区块&quot;(Building terrain / 加载卡顿)的根源之一:不是算一个 chunk 慢,而是要把一大片邻居都拉到对应阶段才能交付中心那一个。</p><hr><h2 id="六、踩坑与反直觉" tabindex="-1">六、踩坑与反直觉 <a class="header-anchor" href="#六、踩坑与反直觉" aria-label="Permalink to &quot;六、踩坑与反直觉&quot;">​</a></h2><p><strong>1. &quot;重新生成会不会把我家删了?&quot;</strong> 不会。生成只负责<strong>原始地形</strong>。你改过的方块作为增量单独存盘(后续讲存储时会展开),加载时是&quot;先按种子算原始地形,再叠加你的改动&quot;。原始地形可重算,改动不可重算——两者分开存,这是整个设计的地基。</p><p><strong>2. 同种子不同版本,世界不一样。</strong> 确定性只在<strong>同一版本的生成算法</strong>下成立。Minecraft 大版本经常重写地形(最著名的是 1.18 把地形和洞穴生成整个换掉),所以同一个种子在 1.16 和 1.18 里完全是两个世界。存档里的 <code>DataVersion</code> 标记着它由哪个版本生成,跨版本加载时旧区块保持原样、新区块用新算法——于是老世界里常见一条&quot;地形断层带&quot;,正是新旧生成算法在你当年探索边界处接缝的痕迹。</p><p><strong>3. 生物群系不是&quot;画&quot;出来的板块。</strong> 别用&quot;先有一张生物群系地图、再填地形&quot;的旧心智。现代实现是反过来的:<strong>先有连续的气候噪声场,生物群系是气候坐标的查表结果。</strong> 所以 biome 边界其实是噪声等值线,过渡自然而非硬切。</p><p><strong>4. 洞穴为什么有的是细管、有的是巨洞?</strong> 因为它们来自 3D 噪声 + 雕刻器(carver)两套机制叠加。3D &quot;奶酪/面条&quot;噪声负责大尺度空腔,carver 负责蜿蜒隧道,两者尺度不同,叠出来就有粗有细。</p><p><strong>5. 噪声查询是无副作用的,可并行。</strong> 正因为 <code>noise(x,z)</code> 是纯函数、不依赖访问顺序,地形生成天然适合多线程:不同 chunk 的 <code>noise</code> 阶段可以并行算,互不干扰。串行瓶颈主要在跨 chunk 的 <code>features</code> 阶段,而不是噪声本身。</p><hr><h2 id="七、串联" tabindex="-1">七、串联 <a class="header-anchor" href="#七、串联" aria-label="Permalink to &quot;七、串联&quot;">​</a></h2><p>把这一篇放回整条主线:</p><ul><li><strong>承接 01(体素世界)</strong>:上一篇说&quot;世界由 chunk 和 16³ section 的方块网格组成,但无限世界不可能全量存&quot;。这一篇就是那句话的下半段——<strong>网格里每个方块的初始值,由种子+噪声当场算出</strong>,所以&quot;无限&quot;才成立。</li><li><strong>接着 03(渲染)</strong>:噪声只决定&quot;每格是什么方块&quot;,算完得到的是一片纯数据的方块网格;怎么把这堆方块<strong>高效画到屏幕上</strong>(只画看得见的面、合并成一个 mesh),是渲染篇的事。</li><li><strong>呼应 08(存储)</strong>:生成 vs 存储的分工,正是本系列的主线——&quot;能算出来的就不存&quot;。地形能算,所以不存;改动算不出来,所以才存增量。而 <code>DataVersion</code> 这个字段,就是连接&quot;哪个版本的生成算法&quot;和&quot;存档怎么迁移&quot;的关键标记,存储篇会再展开。</li></ul><p>一句话收束:<strong>种子是世界的全部信息,噪声是把它展开成地形的函数,流水线阶段是让跨区块结构不破缝的工程手段。三者合起来,才让&quot;无限世界 + 有限硬盘&quot;这个矛盾不再矛盾。</strong></p>`,66)])])}const h=t(e,[["render",p]]);export{g as __pageData,h as default};
